// 2. PASS THE TEMPLATE
return [{ json: { html_template: template } }];

// 1. GET TEMPLATE & CONFIG
const template = $('Load email template').first().json.html_template;
const config = $('Set newsletter config').first().json;

// 2. CLEAN AI OUTPUT
let aiRaw = $('Generate newsletter content').first().json.output;
if (typeof aiRaw === 'string') {
    aiRaw = aiRaw.replace(/```json/g, '').replace(/```/g, '').trim();
}

let aiData;
try {
    aiData = typeof aiRaw === 'object' ? aiRaw : JSON.parse(aiRaw);
} catch (e) {
    aiData = { 
        intro_text: "<p>Here is your weekly update.</p>", 
        product_section: "",
        news_section: aiRaw 
    };
}

// 3. GET DATE
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

// 4. MERGE VARIABLES (The Magic Step)
let finalEmail = template
    .replace('{{LOGO_URL}}', config.logo_url)
    .replace('{{SUBSCRIBE_URL}}', config.subscribe_url)
    .replace('{{DATE}}', today)

    // NEW: Replace the 3 Text Fields
    .replace(/{{NEWSLETTER_NAME}}/g, config.newsletter_name) // Global replace in header & footer
    .replace('{{EMAIL_TITLE}}', config.email_title)
    .replace('{{AUTHOR}}', config.author_name)

    // Content Sections
    .replace('{{INTRO_TEXT}}', aiData.intro_text || "")
    .replace('{{PRODUCT_SECTION}}', aiData.product_section || "") 
    .replace('{{NEWS_SECTION}}', aiData.news_section || "");

// 5. OUTPUT
return [{ json: { html_email: finalEmail } }];

// DIRECT ACCESS SCRIPT
// This ignores the Merge/Rename nodes and grabs clean data directly from the source.

let allArticles = [];

// 1. Grab Global News directly from the search node
try {
    // We access the 'Search external news (Tavily)' node directly
    const newsItems = $('Search external news (Tavily)').all();

    // Loop through results in case there are multiple items
    for (const item of newsItems) {
        if (item.json.results && Array.isArray(item.json.results)) {
            allArticles = allArticles.concat(item.json.results);
        }
    }
} catch (error) {
    // If the node didn't run, just skip it
    console.log("News search data not found");
}

// 2. Grab Internal Blog Posts directly from the search node
try {
    // We access the 'Search company blog (Tavily)' node directly
    const blogItems = $('Search company blog (Tavily)').all();

    for (const item of blogItems) {
        if (item.json.results && Array.isArray(item.json.results)) {
            allArticles = allArticles.concat(item.json.results);
        }
    }
} catch (error) {
    // If the node didn't run, just skip it
    console.log("Blog search data not found");
}

// 3. Output the combined list
return [{ json: { research_data: allArticles } }];
